/**
 * Normalize tags to lowercase trimmed strings
 * @param {string|string[]} tags
 * @returns {string[]}
 */
function normalizeTags(tags) {
  if (!tags) return [];
  if (typeof tags === 'string') {
    // Split by comma and trim
    return tags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
  }
  if (Array.isArray(tags)) {
    return tags.map(t => String(t).trim().toLowerCase()).filter(t => t.length > 0);
  }
  return [];
}

/**
 * Filter problems by difficulty
 * @param {Array} problems
 * @param {string} difficulty
 * @returns {Array}
 */
function filterByDifficulty(problems, difficulty) {
  if (!difficulty) return problems;
  const diffLower = difficulty.toLowerCase();
  return problems.filter(p => p.difficulty && p.difficulty.toLowerCase() === diffLower);
}

/**
 * Filter problems by skill tags (case-insensitive, all tags must be present)
 * @param {Array} problems
 * @param {string|string[]} tags
 * @returns {Array}
 */
function filterByTags(problems, tags) {
  const normalizedTags = normalizeTags(tags);
  if (normalizedTags.length === 0) return problems;

  return problems.filter(problem => {
    if (!problem.tags || !Array.isArray(problem.tags)) return false;
    const problemTags = problem.tags.map(t => t.toLowerCase());
    // Check all normalizedTags are present in problemTags
    return normalizedTags.every(tag => problemTags.includes(tag));
  });
}

/**
 * Sort problems by stable criteria: difficulty asc, then id asc
 * @param {Array} problems
 * @returns {Array}
 */
function stableSortProblems(problems) {
  // Define difficulty order
  const difficultyOrder = { easy: 1, medium: 2, hard: 3 };

  return problems.slice().sort((a, b) => {
    const diffA = difficultyOrder[a.difficulty?.toLowerCase()] || 99;
    const diffB = difficultyOrder[b.difficulty?.toLowerCase()] || 99;
    if (diffA !== diffB) return diffA - diffB;
    // fallback to id ascending
    if (a.id < b.id) return -1;
    if (a.id > b.id) return 1;
    return 0;
  });
}

